from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    # Helper to lower‑case genre/style names for natural phrasing
    def lc(text: str) -> str:
        return text.lower()

    # Index triples by subject for quick lookup
    from collections import defaultdict, OrderedDict

    subj_map: dict[str, list[Triple]] = defaultdict(list)
    order: list[str] = []  # preserve first‑seen subject order
    for t in triples:
        subj_map[t.subject].append(t)
        if t.subject not in order:
            order.append(t.subject)

    sentences: list[str] = []

    for subj in order:
        parts: list[str] = []
        triples_here = subj_map[subj]

        # ----- genre handling (with possible stylisticOrigin of the genre) -----
        genre_triples = [t for t in triples_here if t.predicate == "genre"]
        if genre_triples:
            genre_phrases = []
            for gt in genre_triples:
                g = gt.object
                # avoid duplicate “music” word
                g_display = g if "music" in g.lower() else f"{g} music"
                phrase = f"{subj} plays {lc(g_display)}"
                # check for stylisticOrigin where the genre is subject
                for t in triples:
                    if t.subject == g and t.predicate == "stylisticOrigin":
                        phrase += f", which originated from {lc(t.object)}"
                        break
                genre_phrases.append(phrase)
            # join multiple genre clauses with “and”
            if len(genre_phrases) == 1:
                parts.append(genre_phrases[0])
            else:
                parts.append(" and ".join(genre_phrases))

        # ----- associated band / musical artist -----
        assoc = [t for t in triples_here if t.predicate == "associatedBand/associatedMusicalArtist"]
        if assoc:
            # collect all associated bands/artists and join with commas and 'and'
            bands = [t.object for t in assoc]
            if len(bands) == 1:
                band_phrase = bands[0]
            else:
                band_phrase = ", ".join(bands[:-1]) + " and " + bands[-1]
            parts.append(f"{subj} is associated with {band_phrase}")

        # ----- basic personal info -----
        # Aggregate origins first
        origins = [t.object for t in triples_here if t.predicate == "origin"]
        if origins:
            combined_origin = ", ".join(origins)
            parts.append(f"{subj} originates from {combined_origin}")

        for t in triples_here:
            s, p, o = t.subject, t.predicate, t.object
            if p in ("birthDate", "birthYear"):
                parts.append(f"{subj} was born in {o}")
            elif p in ("deathDate", "deathPlace"):
                parts.append(f"{subj} died in {o}")
            elif p == "birthPlace":
                parts.append(f"{subj} was born in {o}")
            elif p == "origin":
                continue  # already handled
            elif p == "instrument":
                parts.append(f"{subj} plays the {o}")
            elif p == "occupation":
                parts.append(f"{subj} works as {o}")
            elif p == "nationality":
                parts.append(f"{subj} is {o}")
            elif p == "recordLabel":
                parts.append(f"{subj} is signed to {o}")
            elif p == "background":
                parts.append(f"{subj} has a background as {o}")
            elif p == "activeYearsStartYear":
                parts.append(f"{subj} started activity in {o}")
            elif p == "activeYearsEndYear":
                parts.append(f"{subj} ended activity in {o}")

        # ----- relational predicates where object is primary -----
        relational_predicates = {
            "leader", "capital", "currency", "anthem", "parentCompany", "location",
            "governingBody", "leaderTitle", "country", "isPartOf", "derivative",
            "bandMember"
        }
        for t in triples_here:
            if t.predicate in relational_predicates:
                parts.append(f"{t.object} is the {t.predicate} of {subj}")

        # Combine parts for this subject
        if parts:
            if len(parts) == 1:
                sentences.append(parts[0] + ".")
            else:
                sentences.append(", ".join(parts[:-1]) + ", and " + parts[-1] + ".")

    # ----- additional relational clauses that involve other subjects -----
    extra_clauses = []
    for t in triples:
        if t.predicate == "derivative":
            extra_clauses.append(f"{t.object} is a derivative of {t.subject}")
        elif t.predicate == "musicFusionGenre":
            extra_clauses.append(f"{t.object} is a music fusion genre of {t.subject}")
        elif t.predicate == "musicSubgenre":
            extra_clauses.append(f"{t.object} is a music subgenre of {t.subject}")
        elif t.predicate == "stylisticOrigin":
            extra_clauses.append(f"{t.subject} has stylistic origin in {t.object}")

    if extra_clauses:
        sentences.append(", ".join(extra_clauses) + ".")

    # Join sentences for different subjects
    return " ".join(sentences)

# EVOLVE-BLOCK-END
